import{_ as n,C as r,o as e,c as s,a2 as i,b as d,w as o,a as l,E as c,a3 as h}from"./chunks/framework.B72_uj9U.js";const P=JSON.parse('{"title":"Pi — Benchmarks & Adoption Metrics","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/pi-coding-agent/benchmarks.md","filePath":"research/agents/pi-coding-agent/benchmarks.md"}'),m={name:"research/agents/pi-coding-agent/benchmarks.md"};function p(u,t,g,b,y,f){const a=r("Mermaid");return e(),s("div",null,[t[1]||(t[1]=i('<h1 id="pi-—-benchmarks-adoption-metrics" tabindex="-1">Pi — Benchmarks &amp; Adoption Metrics <a class="header-anchor" href="#pi-—-benchmarks-adoption-metrics" aria-label="Permalink to &quot;Pi — Benchmarks &amp; Adoption Metrics&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Pi does not currently appear on the Terminal-Bench 2.0 leaderboard or other major coding agent benchmarks. This is consistent with the project&#39;s philosophy — Pi is not optimized for benchmark performance, and Mario Zechner has not prioritized benchmark submission. The project&#39;s value proposition is flexibility and control, not raw benchmark scores.</p><p>This file instead covers community adoption metrics, ecosystem health indicators, and comparative analysis.</p><h2 id="benchmark-absence-—-context" tabindex="-1">Benchmark Absence — Context <a class="header-anchor" href="#benchmark-absence-—-context" aria-label="Permalink to &quot;Benchmark Absence — Context&quot;">​</a></h2><h3 id="why-pi-isn-t-on-terminal-bench" tabindex="-1">Why Pi Isn&#39;t on Terminal-Bench <a class="header-anchor" href="#why-pi-isn-t-on-terminal-bench" aria-label="Permalink to &quot;Why Pi Isn&#39;t on Terminal-Bench&quot;">​</a></h3><p>Several factors explain Pi&#39;s absence from benchmark leaderboards:</p><ol><li><strong>Philosophy mismatch</strong>: Terminal-Bench measures out-of-the-box performance on coding tasks. Pi&#39;s strength is customizability, which benchmarks don&#39;t capture.</li><li><strong>Minimal defaults</strong>: With only four built-in tools, Pi&#39;s default configuration is less optimized for complex coding benchmarks than agents with built-in search, lint-test-fix cycles, and planning.</li><li><strong>Extension-dependent performance</strong>: Pi&#39;s real-world performance depends heavily on which extensions are installed. A Pi instance with git checkpointing, code search, and test-running extensions would perform very differently from a stock Pi instance.</li><li><strong>Project priorities</strong>: Mario Zechner focuses on architecture and extensibility rather than benchmark optimization.</li></ol><h3 id="what-benchmarks-would-show" tabindex="-1">What Benchmarks Would Show <a class="header-anchor" href="#what-benchmarks-would-show" aria-label="Permalink to &quot;What Benchmarks Would Show&quot;">​</a></h3><p>A stock Pi (four tools, no extensions) would likely score below agents with more built-in capabilities (Claude Code, Aider) on standard benchmarks. However, a well-configured Pi with appropriate extensions and skills could potentially match or exceed these scores, as the extension system allows implementing the same strategies (planning, lint-test-fix cycles, code search) that give other agents their benchmark edges.</p><p>This highlights an interesting question for coding agent evaluation: <strong>should benchmarks measure the agent as shipped, or the agent as configured by a skilled user?</strong></p><h2 id="community-adoption-metrics" tabindex="-1">Community Adoption Metrics <a class="header-anchor" href="#community-adoption-metrics" aria-label="Permalink to &quot;Community Adoption Metrics&quot;">​</a></h2><h3 id="github-activity" tabindex="-1">GitHub Activity <a class="header-anchor" href="#github-activity" aria-label="Permalink to &quot;GitHub Activity&quot;">​</a></h3><p>The pi-mono repository and surrounding ecosystem provide several adoption signals:</p><ul><li><strong>Repository</strong>: github.com/badlogic/pi-mono</li><li><strong>Creator credibility</strong>: Mario Zechner (@badlogic) is the creator of libGDX, one of the most popular open-source game frameworks, with a strong track record in developer tooling</li><li><strong>Active development</strong>: Regular commits and releases</li><li><strong>Issue activity</strong>: Active issue tracker with community contributions</li></ul><h3 id="npm-ecosystem" tabindex="-1">npm Ecosystem <a class="header-anchor" href="#npm-ecosystem" aria-label="Permalink to &quot;npm Ecosystem&quot;">​</a></h3><p>Pi&#39;s packages are published to npm under the <code>@mariozechner</code> scope:</p><ul><li><code>@mariozechner/pi-coding-agent</code> — The main CLI</li><li><code>@mariozechner/pi-ai</code> — Unified LLM API (independently useful)</li><li><code>@mariozechner/pi-agent-core</code> — Agent runtime</li><li><code>@mariozechner/pi-tui</code> — Terminal UI framework</li><li><code>@mariozechner/pi-web-ui</code> — Web components</li><li><code>@mariozechner/pi-mom</code> — Slack bot</li><li><code>@mariozechner/pi-pods</code> — GPU pod management</li></ul><p>Community packages use the <code>pi-package</code> npm keyword for discoverability.</p><h3 id="community-infrastructure" tabindex="-1">Community Infrastructure <a class="header-anchor" href="#community-infrastructure" aria-label="Permalink to &quot;Community Infrastructure&quot;">​</a></h3><ul><li><strong>Discord</strong>: Active community server for discussion, package sharing, and support</li><li><strong>awesome-pi-agent</strong>: Curated list of Pi resources, packages, and integrations</li><li><strong>Comparison projects</strong>: pi-vs-claude-code and similar repositories comparing Pi to other agents</li></ul><h2 id="ecosystem-health-indicators" tabindex="-1">Ecosystem Health Indicators <a class="header-anchor" href="#ecosystem-health-indicators" aria-label="Permalink to &quot;Ecosystem Health Indicators&quot;">​</a></h2><h3 id="third-party-package-growth" tabindex="-1">Third-Party Package Growth <a class="header-anchor" href="#third-party-package-growth" aria-label="Permalink to &quot;Third-Party Package Growth&quot;">​</a></h3><p>The health of Pi&#39;s ecosystem is best measured by the diversity and quality of community-built packages:</p><table tabindex="0"><thead><tr><th>Package</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>pi-skills</td><td>Skills collection</td><td>Common skills for various frameworks and tools</td></tr><tr><td>pi-messenger</td><td>Extension</td><td>Messaging platform integrations</td></tr><tr><td>pi-mcp-adapter</td><td>Extension</td><td>MCP protocol support for Pi</td></tr><tr><td>pi-web-access</td><td>Extension</td><td>Web browsing capabilities</td></tr></tbody></table><h3 id="integration-with-multi-agent-systems" tabindex="-1">Integration with Multi-Agent Systems <a class="header-anchor" href="#integration-with-multi-agent-systems" aria-label="Permalink to &quot;Integration with Multi-Agent Systems&quot;">​</a></h3><p>Pi&#39;s four modes of operation (especially RPC and SDK) have enabled integration with larger systems:</p><ul><li><strong>Overstory</strong>: Multi-agent orchestrator that can use Pi as a component agent</li><li><strong>Agent of Empires</strong>: Another orchestration framework with Pi integration</li><li><strong>pi-mom</strong>: First-party Slack bot demonstrating the RPC integration pattern</li></ul><h3 id="developer-adoption-signals" tabindex="-1">Developer Adoption Signals <a class="header-anchor" href="#developer-adoption-signals" aria-label="Permalink to &quot;Developer Adoption Signals&quot;">​</a></h3><p>Pi appeals to a specific developer segment:</p><ul><li><strong>Power users</strong> who want full control over their coding agent</li><li><strong>Extension builders</strong> who want to customize agent behavior deeply</li><li><strong>Multi-model users</strong> who switch between LLM providers</li><li><strong>Self-hosters</strong> who want to run agents against local or private models</li></ul><p>This is deliberately a niche audience. Mario Zechner has joked that the project name (&quot;pi&quot;) is &quot;so there will never be any users&quot; — intentionally un-Google-able.</p><h2 id="comparative-analysis" tabindex="-1">Comparative Analysis <a class="header-anchor" href="#comparative-analysis" aria-label="Permalink to &quot;Comparative Analysis&quot;">​</a></h2><h3 id="feature-comparison-not-a-benchmark" tabindex="-1">Feature Comparison (Not a Benchmark) <a class="header-anchor" href="#feature-comparison-not-a-benchmark" aria-label="Permalink to &quot;Feature Comparison (Not a Benchmark)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Claude Code</th><th>Aider</th><th>Goose</th><th>Pi</th></tr></thead><tbody><tr><td>Default tools</td><td>~15</td><td>Edit formats</td><td>~10 toolkits</td><td>4</td></tr><tr><td>Extension system</td><td>Limited</td><td>No</td><td>Toolkits</td><td>Full TypeScript API</td></tr><tr><td>LLM providers</td><td>1 (Anthropic)</td><td>20+</td><td>Multiple</td><td>15+ (unified API)</td></tr><tr><td>MCP support</td><td>Yes</td><td>No</td><td>Yes</td><td>Via extension</td></tr><tr><td>Sub-agents</td><td>Yes</td><td>No</td><td>No</td><td>Via extension</td></tr><tr><td>Session branching</td><td>No</td><td>No</td><td>No</td><td>Yes</td></tr><tr><td>System prompt control</td><td>No</td><td>Limited</td><td>No</td><td>Full</td></tr><tr><td>Background tasks</td><td>Yes</td><td>No</td><td>No</td><td>Via tmux</td></tr></tbody></table><h3 id="positioning" tabindex="-1">Positioning <a class="header-anchor" href="#positioning" aria-label="Permalink to &quot;Positioning&quot;">​</a></h3><p>Pi occupies a unique position in the terminal coding agent landscape:</p>',37)),(e(),d(h,null,{default:o(()=>[c(a,{id:"mermaid-444",class:"mermaid",graph:"quadrantChart%0A%20%20%20%20title%20%22Agent%20Positioning%3A%20Built-in%20Features%20vs%20Extensibility%22%0A%20%20%20%20x-axis%20%22Less%20Extensible%22%20--%3E%20%22More%20Extensible%22%0A%20%20%20%20y-axis%20%22Fewer%20Built-in%20Features%22%20--%3E%20%22More%20Built-in%20Features%22%0A%20%20%20%20%22Claude%20Code%22%3A%20%5B0.2%2C%200.9%5D%0A%20%20%20%20%22Goose%22%3A%20%5B0.25%2C%200.7%5D%0A%20%20%20%20%22Aider%22%3A%20%5B0.2%2C%200.6%5D%0A%20%20%20%20%22Pi%20(stock)%22%3A%20%5B0.85%2C%200.2%5D%0A%20%20%20%20%22Pi%20(with%20extensions)%22%3A%20%5B0.85%2C%200.65%5D%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=i('<p>Pi with extensions can reach feature parity with more built-in agents, but requires user effort to configure. The trade-off is: <strong>predictability and control vs. out-of-the-box capability</strong>.</p><h2 id="recommendations-for-evaluation" tabindex="-1">Recommendations for Evaluation <a class="header-anchor" href="#recommendations-for-evaluation" aria-label="Permalink to &quot;Recommendations for Evaluation&quot;">​</a></h2><p>When evaluating Pi, consider:</p><ol><li><strong>Don&#39;t compare stock Pi to fully-featured agents</strong> — it&#39;s comparing a toolkit to a finished product</li><li><strong>Evaluate the extension ecosystem</strong> — a Pi with good extensions can match other agents</li><li><strong>Consider the stability value</strong> — no surprise behavior changes on updates</li><li><strong>Consider the customization value</strong> — ability to perfectly tune the agent to your workflow</li><li><strong>Watch ecosystem growth</strong> — the number and quality of community packages indicates long-term viability</li></ol>',4))])}const w=n(m,[["render",p]]);export{P as __pageData,w as default};
